// modules/teams/routes/renameTeam.ts
import { requireUser, getSession } from '/lib/auth';
import { Result, ok, err } from '/lib/result';
import { parseBody } from '/lib/validate';
import { Team } from '/lib/types';
import { query } from '/lib/db';

export async function renameTeam(req: Request): Promise<Response> {
  const user = await requireUser(req);
  if (!user.isAdmin) return err({ code: 'UNAUTHORIZED', message: 'Admin access required' });

  const body = parseBody<{ name: string }>(req, { name: 'string' });
  const teamId = parseInt(req.params.teamId);

  try {
    const session = await getSession(req);
    if (!session) return err({ code: 'UNAUTHORIZED', message: 'Session expired' });

    // Ensure the user is an admin of the team
    const team = await query<Team>('SELECT * FROM teams WHERE id = $1 AND admin_id = $2', [teamId, user.id]);
    if (!team) return err({ code: 'NOT_FOUND', message: 'Team not found' });

    // Rename the team
    await query('UPDATE teams SET name = $1 WHERE id = $2', [body.name, teamId]);

    return ok({ message: 'Team renamed successfully' });
  } catch (error) {
    return err({ code: 'INTERNAL_ERROR', message: 'Failed to rename team' });
  }
}

